import os, time, base64, requests
from collections import defaultdict
from flask import Flask, request, jsonify, Response
from flask_cors import CORS

app = Flask(__name__)
CORS(app)

API_KEY = os.environ.get("ANTHROPIC_API_KEY", "")
ANTHROPIC_URL = "https://api.anthropic.com/v1/messages"
_B64 = ""
HTML = base64.b64decode(_B64).decode("utf-8")

request_log = defaultdict(list)
RATE_LIMIT = 20
RATE_WINDOW = 3600

def is_rate_limited(ip):
    now = time.time()
    request_log[ip] = [t for t in request_log[ip] if now - t < RATE_WINDOW]
    if len(request_log[ip]) >= RATE_LIMIT:
        return True
    request_log[ip].append(now)
    return False

@app.route("/")
def index():
    return Response(HTML, mimetype="text/html")

@app.route("/health")
def health():
    return jsonify({"status": "ok", "key_configured": bool(API_KEY)})

@app.route("/api/generate", methods=["POST"])
def generate():
    client_ip = request.headers.get("X-Forwarded-For", request.remote_addr)
    if client_ip:
        client_ip = client_ip.split(",")[0].strip()
    if is_rate_limited(client_ip):
        return jsonify({"error": {"message": "Rate limit reached. Try again in an hour."}}), 429
    if not API_KEY:
        return jsonify({"error": {"message": "Server API key not configured."}}), 500
    body = request.get_json()
    if not body:
        return jsonify({"error": {"message": "Invalid request body."}}), 400
    try:
        resp = requests.post(
            ANTHROPIC_URL,
            headers={"x-api-key": API_KEY, "anthropic-version": "2023-06-01", "content-type": "application/json"},
            json=body,
            timeout=120,
        )
        return jsonify(resp.json()), resp.status_code
    except requests.exceptions.Timeout:
        return jsonify({"error": {"message": "Request timed out."}}), 504
    except Exception as e:
        return jsonify({"error": {"message": str(e)}}), 500

if __name__ == "__main__":
    port = int(os.environ.get("PORT", 5000))
    app.run(host="0.0.0.0", port=port, debug=False)
